INSERT INTO `frontends` VALUES (1,'seo.data','{\"seo_image\":\"1\",\"keywords\":[\"exchange platform\",\"currency exchange platform\",\"changalab\",\"usd to inr\",\"currency exchnage\",\"easy exchange\",\"money exhcngae\",\"bitcoin to usd\",\"money exchange\",\"crypto currency exchange\",\"crypto currency\"],\"description\":\"ChangaLab can be explained as a network of buyers and sellers, who transfer currency between each other or for their own. It is the means by which individuals, and companies convert one currency into another. This Currency Exchange Platform is the most advanced script in Codecanyon. The Currency Exchange Platform is endlessly appealing, feature-loaded, customized, and possesses the remarkable capability of running on all devices and operating systems.\",\"social_title\":\"ChangaLab - Currency Exchange Platform\",\"social_description\":\"ChangaLab can be explained as a network of buyers and sellers, who transfer currency between each other or for their own. It is the means by which individuals, companies convert one currency into another. This Currency Exchange Platform is the most advanced script in Codecanyon. The Currency Exchange Platform is endlessly appealing, feature-loaded, customized, and possesses the remarkable capability of running on all devices and operating systems.\",\"image\":\"67d25fa7ca5881741840295.png\"}',NULL,NULL,'','2020-07-04 05:42:52','2025-03-12 22:31:36'),(24,'about.content','{\"has_image\":\"1\",\"heading\":\"About Changalab\",\"subheading\":\"The smartest way to collect, convert and transfer money globally\",\"description\":\"At Changalab, our mission is to create the world\\u2019s best exchange platform for individuals and international businesses.<div><br \\/><\\/div><div><div>Changalab was born back in 2016 by innovators in a London basement armed with ten years of banking experience, an entrepreneurial spirit, and a desire to provide customers a real alternative to the big banks. Since then, we\\u2019ve grown exponentially, and with a global team around 600 strong, have become a market-leading, multi-award winning, bank-beating, rapidly-growing, fun-loving international payments company.<\\/div><\\/div><div><br \\/><\\/div><div>Currently, more than 250,000 global customers &amp; 150,000 global businesses choose Changalab for their international transfers. We have transferred \\u00a370 Billion for our customers since we launched, more than 1 million transfers per year<br \\/><\\/div>\",\"about_image\":\"63cfac0241e491674554370.png\"}',NULL,'orange_oasis',NULL,'2020-10-27 06:51:20','2023-01-24 03:59:31'),(25,'blog.content','{\"heading\":\"Our Latest News\",\"subheading\":\"Lorem ipsum dolor sit amet consectetuer adipiscing elit. Aenean modo lula eget dolor. Aenean massa.\"}',NULL,'orange_oasis',NULL,'2020-10-27 06:51:34','2023-01-23 06:56:21'),(28,'counter.content','{\"has_image\":\"1\",\"background_image\":\"63a2e69ff20351671620255.jpg\"}',NULL,'orange_oasis',NULL,'2020-10-27 07:04:02','2022-12-21 04:57:36'),(31,'social_icon.element','{\"title\":\"Facebook\",\"social_icon\":\"<i class=\\\"las la-expand\\\"><\\/i>\",\"url\":\"https:\\/\\/www.google.com\\/\"}',NULL,'orange_oasis',NULL,'2020-11-11 10:07:30','2022-10-20 11:15:48'),(33,'feature.content','{\"heading\":\"Our Special Features\",\"subheading\":\"We support the most secure services and features. This secured website supports a user-friendly interface and various attractive features that ready to use.\"}',NULL,'orange_oasis',NULL,'2021-01-03 05:40:54','2022-10-20 11:15:48'),(34,'feature.element','{\"title\":\"Safe and Secure\",\"description\":\"We value your money and your privacy. We have deployed the best systems to ensure that your money and your account.\",\"feature_icon\":\"<i class=\\\"fas fa-hand-holding-heart\\\"><\\/i>\"}',NULL,'orange_oasis',NULL,'2021-01-03 05:41:02','2022-10-20 11:15:48'),(35,'service.element','{\"trx_type\":\"withdraw\",\"service_icon\":\"<i class=\\\"las la-highlighter\\\"><\\/i>\",\"tit