and support!\r\n\r\nHappy exchanging!&nbsp;</p><p data-start=\"86\" data-end=\"98\"><b>{{site_name}}</b></p>','',NULL,'{\"exchange\":\"Exchange Id For the Exchange\", \"amount\":\"Exchange bonus amount\", \"currency\":\"Received bonus currency\"}',1,NULL,NULL,0,NULL,0,NULL,0,NULL,'2025-02-18 20:27:24'),(26,'REGISTER_BONUS','Registration Bonus','Registration bonus for signing up',NULL,'<div><div style=\"font-family: Montserrat, sans-serif;\">You get {{amount}}&nbsp;{{site_currency}} for your registration.</div><div style=\"font-family: Montserrat, sans-serif;\"><br></div><div style=\"font-family: Montserrat, sans-serif;\">Transaction Number : {{trx}}</div><div style=\"font-family: Montserrat, sans-serif;\"><br></div><span style=\"color: rgb(33, 37, 41); font-family: Montserrat, sans-serif;\">Your Current Balance is :&nbsp;</span><font style=\"font-family: Montserrat, sans-serif;\"><span style=\"font-weight: bolder;\">{{post_balance}}&nbsp; {{site_currency}}&nbsp;</span></font></div>','You get {{amount}} {{site_currency}} for your registration.','You get {{amount}} {{site_currency}} for your registration.','{\"trx\":\"Transaction number\",\"amount\":\"Bonus amount\",\"post_balance\":\"Balance of the user after this transaction\"}',1,NULL,NULL,0,NULL,0,NULL,0,'2021-11-03 06:00:00','2025-02-27 08:15:11');
